{"variables":{"owner":"glossia","repo":"glossia","owner":"glossia","repo":"glossia"},"query":"query GetRepositoryDefaultBranch($owner: String!, $repo: String!) {
  repository(owner: $owner, name: $repo) {
    defaultBranchRef {
      name
    }
  }
}
"}

{"variables":{"owner":"glossia","repo":"glossia"},"query":"query getMostRecentCommit($owner: String!, $repo: String!) {
  repository(owner: $owner, name: $repo) {
    ref(qualifiedName: "refs/heads/main") {
      target {
        ... on Commit {
          history(first: 100) {
            edges {
              node {
                messageHeadline
                oid
                committedDate
                author {
                  name
                  email
                }
              }
            }
          }
        }
      }
    }
  }
}
"}
